#include "lorawan_otaa.h"
#include <lmic.h>
#include <hal/hal.h>
static const lmic_pinmap lmic_pins={.nss=18,.rxtx=LMIC_UNUSED_PIN,.rst=14,.dio={26,33,32}};
static bool _joined=false;
void os_getArtEui(u1_t*buf){}
void os_getDevEui(u1_t*buf){}
void os_getDevKey(u1_t*buf){}
void onEvent(ev_t ev){if(ev==EV_JOINED){_joined=true;Serial.println("[lora] Joined!");}}
void lorawan_setup(const uint8_t*ae,const uint8_t*de,const uint8_t*ak){os_init();LMIC_reset();LMIC_startJoining();Serial.println("[lorawan] Starting OTAA join");}
void lorawan_loop(){os_runloop_once();}
bool lorawan_send(const uint8_t*d,uint8_t l){if(!_joined)return false;LMIC_setTxData2(1,(uint8_t*)d,l,0);return true;}
bool lorawan_joined(){return _joined;}
